          display: flex;
        }

        /* ===== CLOSE BUTTON ===== */
        .nav-mobile .mobile-close {
          position: absolute;
          top: 12px;
          right: 16px;
          background: none;
          border: none;
          color: rgba(255, 248, 237, 0.6);
          font-size: 1.4rem;
          cursor: pointer;
          transition: var(--transition);
          padding: 0.3rem;
          line-height: 1;
        }

        .nav-mobile .mobile-close:hover {
          color: #fff2d8;
          transform: rotate(90deg);
        }

        .nav-mobile a {
          padding: 0.75rem 1rem;
          border-radius: 12px;
          text-decoration: none;
          color: rgba(255, 248, 237, 0.76);
          font-weight: 500;
          transition: var(--transition);
        }

        .nav-mobile a:hover,
        .nav-mobile a.active {
          color: #fff2d8;
          background: rgba(255, 248, 237, 0.10);
        }

        .nav-mobile .nav-cta-mobile {
          background: linear-gradient(135deg, #fff2d8, #c98545);
          color: #24140f !important;
          text-align: center;
          margin-top: 0.5rem;
          border-radius: 12px;
          font-weight: 700;
        }

        @media (max-width: 768px) {
          .nav-links {
            display: none !important;
          }
          .nav-toggle {
            display: block !important;
          }
          .navbar-premium {
            padding: 0.4rem 1rem;
            top: 10px;
            border-radius: 18px;
          }
        }
      `}</style>

      <nav className={`navbar-premium ${scrolled ? 'scrolled' : ''}`}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Link to="/" className="navbar-brand">
            <span className="brand-icon"><i className="fas fa-code"></i></span>
            <span className="brand-text">4naa</span>
          </Link>

          <div className="nav-links">
            <Link to="/" className={`nav-link-premium ${isActive('/') ? 'active' : ''}`}>Beranda</Link>

            {!isProjectPage && (
              <Link to="/project" className={`nav-link-premium ${isActive('/project') ? 'active' : ''}`}>Project</Link>
            )}

            <a href="/#skills" className="nav-link-premium">Skill</a>

            {!isProjectPage && (
              <Link to="/project" className="nav-link-premium nav-cta">
                <i className="fas fa-folder-open me-1"></i>Lihat Project
              </Link>
            )}
          </div>

          <button 
            className="nav-toggle" 
            ref={toggleRef}
            onClick={() => setMobileOpen(!mobileOpen)}
          >
            <i className={`fas fa-${mobileOpen ? 'times' : 'bars'}`}></i>
          </button>
        </div>
      </nav>

      {/* ===== MOBILE MENU WITH CLOSE BUTTON ===== */}
      <div className={`nav-mobile ${mobileOpen ? 'open' : ''}`} ref={mobileRef}>
        <button className="mobile-close" onClick={() => setMobileOpen(false)}>
          <i className="fas fa-times"></i>
        </button>

        <Link to="/" className={isActive('/') ? 'active' : ''} onClick={() => setMobileOpen(false)}>Beranda</Link>

        {!isProjectPage && (
          <Link to="/project" className={isActive('/project') ? 'active' : ''} onClick={() => setMobileOpen(false)}>Project</Link>
        )}

        <a href="/#skills" onClick={() => setMobileOpen(false)}>Skill</a>

        {!isProjectPage && (
          <Link to="/project" className="nav-cta-mobile" onClick={() => setMobileOpen(false)}>
            <i className="fas fa-folder-open me-2"></i>Lihat Project
          </Link>
        )}
      </div>

      {/* ===== OVERLAY UNTUK TAP DI LUAR MENU ===== */}
      {mobileOpen && (
        <div 
          style={{
            position: 'fixed',
            inset: 0,
            zIndex: 998,
            backgroundColor: 'transparent',
          }}
          onClick={() => setMobileOpen(false)}
        />
      )}
    </>
  );
}
